choose.when:
SELECT
TOP (${limit})
t.*, -- 解析 location: 巷道-排-列-层-深度 (使用OPENJSON解析，key从0开始) loc.location_column, loc.location_level FROM tasks t WITH (READPAST) CROSS APPLY ( SELECT CAST(MAX(CASE WHEN j.[key] = 2 THEN j.value END) AS INT) AS location_column, CAST(MAX(CASE WHEN j.[key] = 3 THEN j.value END) AS INT) AS location_level FROM OPENJSON('["' + REPLACE(t.location, '-', '","') + '"]') j ) loc WHERE t.status = #{task.status} AND t.is_auto_start = #{task.isAutoStart}
AND t.warehouse_id = #{task.warehouseId}
AND t.end_point = #{task.endPoint}
AND t.aisle_no = #{task.aisleNo}
AND (t.aisle_no IS NULL OR t.aisle_no NOT IN
#{aisle}
)
AND EXISTS ( SELECT 1 FROM STRING_SPLIT(t.device_ids, ',') s WHERE s.value IN
#{item}
) ORDER BY -- 1️ 业务优先级 t.priority DESC, -- 0️ 任务类型（出库优先） CASE t.task_category WHEN 'CK' THEN 3 WHEN 'YK' THEN 2 WHEN 'PD' THEN 1 ELSE 0 END DESC, -- 2️ 层排序：由高到低（降序）- 提前，整体排序 loc.location_level DESC, -- 3️ 列排序：由小到大（升序）- 提前，整体排序 loc.location_column ASC, -- 4️ 深度主序：单伸优先，然后是有 twinsNo 的任务 CASE WHEN t.depth = 'SINGLE' THEN 3 WHEN t.twins_no IS NOT NULL AND t.twins_no != '' THEN 2 ELSE 1 END DESC, -- 5️ 同组分组：让相同 twinsNo 的任务排在一起 CASE WHEN t.twins_no IS NOT NULL AND t.twins_no != '' THEN 0 ELSE 1 END ASC, t.twins_no ASC, -- 6️ 在相同 twinsNo 内，按 depth 排序：FRONT > BACK CASE WHEN t.depth = 'FRONT' THEN 2 WHEN t.depth = 'BACK' THEN CASE WHEN t.front_empty = 1 THEN 2 ELSE 1 END ELSE 0 END DESC, -- 7️ FIFO（创建时间） t.created_at ASC

SELECT *, -- 解析 location: 巷道-排-列-层-深度 CAST(SPLIT_PART(location, '-', 3) AS INT) AS location_column, CAST(SPLIT_PART(location, '-', 4) AS INT) AS location_level FROM tasks WHERE status = #{task.status} AND is_auto_start = #{task.isAutoStart}
AND warehouse_id = #{task.warehouseId}
AND end_point = #{task.endPoint}
AND aisle_no = #{task.aisleNo}
AND (aisle_no IS NULL OR aisle_no NOT IN
#{aisle}
)
AND EXISTS ( SELECT 1 FROM unnest(string_to_array(device_ids, ',')) AS s(value) WHERE s.value IN
#{item}
) ORDER BY -- 0️ 任务类型（出库优先） CASE task_category WHEN 'CK' THEN 3 WHEN 'YK' THEN 2 WHEN 'PD' THEN 1 ELSE 0 END DESC, -- 1️ 业务优先级 priority DESC, -- 7️ FIFO（创建时间） created_at ASC, -- 2️ 层排序：由高到低（降序）- 提前，整体排序 location_level DESC, -- 3️ 列排序：由小到大（升序）- 提前，整体排序 location_column ASC, -- 4️ 深度主序：单伸优先，然后是有 twinsNo 的任务 CASE WHEN depth = 'SINGLE' THEN 3 WHEN twins_no IS NOT NULL AND twins_no != '' THEN 2 ELSE 1 END DESC, -- 5️ 同组分组：让相同 twinsNo 的任务排在一起 CASE WHEN twins_no IS NOT NULL AND twins_no != '' THEN 0 ELSE 1 END ASC, twins_no ASC, -- 6️ 在相同 twinsNo 内，按 depth 排序：FRONT > BACK CASE WHEN depth = 'FRONT' THEN 2 WHEN depth = 'BACK' THEN CASE WHEN front_empty = 1 THEN 2 ELSE 1 END ELSE 0 END DESC
LIMIT ${limit}

SELECT TOP (1) 
FROM tasks t
WHERE t.status = 'pending'
AND t.is_auto_start = 1
AND t.end_point = #{endPoint}
AND t.warehouse_id = #{warehouseId}
AND t.twins_no = #{twinsNo}
ORDER BY ISNULL(t.priority,1) DESC, t.created_at ASC

SELECT 
FROM tasks t
WHERE t.status = 'pending'
AND t.is_auto_start = 1
AND t.end_point = #{endPoint}
AND t.warehouse_id = #{warehouseId}
AND t.twins_no = #{twinsNo}
ORDER BY COALESCE(t.priority,1) DESC, t.created_at ASC
LIMIT 1

select

from tasks where process_instance_id = #{processInstanceId}
limit 1

mapper.update:
UPDATE tasks
SET location = #{location},start_point = #{startPoint},twins_no = #{twinsNo}, depth = #{depth}
WHERE task_number = #{taskNumber}
  and status not in ('executing','completed')
